<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Sorting Algorithm Visualizer</title>
  <style>
    :root {
      color-scheme: dark;
      --background: #090d18;
      --panel: #121827;
      --panel-border: #273147;
      --text: #edf2ff;
      --muted: #95a3bd;
      --accent: #6d7cff;
      --accent-light: #94a0ff;
      --compare: #ffbd59;
      --sorted: #3ddc97;
    }

    * {
      box-sizing: border-box;
    }

    body {
      min-height: 100vh;
      margin: 0;
      display: grid;
      place-items: center;
      padding: 24px;
      overflow-x: hidden;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      color: var(--text);
      background:
        radial-gradient(circle at 15% 10%, #172044 0, transparent 35%),
        radial-gradient(circle at 90% 85%, #17293c 0, transparent 30%),
        var(--background);
    }

    main {
      width: min(100%, 1000px);
    }

    header {
      margin-bottom: 20px;
    }

    h1 {
      margin: 0 0 6px;
      font-size: clamp(1.6rem, 4vw, 2.5rem);
      letter-spacing: -0.04em;
    }

    header p {
      margin: 0;
      color: var(--muted);
    }

    .visualizer {
      padding: clamp(16px, 3vw, 28px);
      border: 1px solid var(--panel-border);
      border-radius: 20px;
      background: color-mix(in srgb, var(--panel) 92%, transparent);
      box-shadow: 0 24px 70px rgb(0 0 0 / 35%);
    }

    #bars {
      position: relative;
      height: min(56vh, 480px);
      min-height: 280px;
      display: flex;
      align-items: flex-end;
      justify-content: center;
      gap: clamp(2px, 0.55vw, 7px);
      padding: 20px 16px 0;
      overflow: hidden;
      border: 1px solid #202b40;
      border-radius: 14px;
      background:
        linear-gradient(rgb(255 255 255 / 3%) 1px, transparent 1px),
        #0c1120;
      background-size: 100% 20%;
    }

    #bars:empty::after {
      content: "The array is empty";
      position: absolute;
      inset: 0;
      display: grid;
      place-items: center;
      color: var(--muted);
    }

    .bar {
      position: relative;
      flex: 1 1 0;
      max-width: 46px;
      min-width: 2px;
      border-radius: 7px 7px 2px 2px;
      background: linear-gradient(180deg, var(--accent-light), var(--accent));
      box-shadow: 0 0 18px rgb(109 124 255 / 18%);
      transition:
        height 110ms ease,
        background 110ms ease,
        transform 110ms ease,
        box-shadow 110ms ease;
    }

    .bar.comparing {
      z-index: 1;
      transform: translateY(-5px);
      background: linear-gradient(180deg, #ffd889, var(--compare));
      box-shadow: 0 0 22px rgb(255 189 89 / 35%);
    }

    .bar.complete {
      background: linear-gradient(180deg, #79edbd, var(--sorted));
      box-shadow: 0 0 18px rgb(61 220 151 / 22%);
    }

    .bar-label {
      position: absolute;
      left: 50%;
      bottom: 100%;
      padding-bottom: 5px;
      transform: translateX(-50%);
      color: #c9d2e7;
      font-size: clamp(0.55rem, 1.2vw, 0.72rem);
      pointer-events: none;
    }

    .controls {
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      gap: 10px;
      margin-top: 18px;
    }

    button {
      min-width: 108px;
      padding: 11px 18px;
      border: 1px solid #34405a;
      border-radius: 10px;
      color: var(--text);
      background: #1a2235;
      font: inherit;
      font-weight: 700;
      cursor: pointer;
      transition: transform 120ms ease, background 120ms ease, border-color 120ms ease;
    }

    button:hover:not(:disabled) {
      transform: translateY(-2px);
      border-color: #53617e;
      background: #222c42;
    }

    button:active:not(:disabled) {
      transform: translateY(0);
    }

    button:focus-visible {
      outline: 3px solid rgb(109 124 255 / 45%);
      outline-offset: 2px;
    }

    button:disabled {
      cursor: not-allowed;
      opacity: 0.55;
    }

    #sort {
      border-color: #7180ff;
      background: var(--accent);
    }

    #sort:hover:not(:disabled) {
      background: #7c89ff;
    }

    #status {
      margin-left: auto;
      color: var(--muted);
      font-size: 0.9rem;
    }

    @media (max-width: 600px) {
      body {
        padding: 12px;
      }

      #bars {
        min-height: 240px;
        padding-inline: 8px;
      }

      .bar-label {
        display: none;
      }

      #status {
        width: 100%;
        margin-left: 0;
      }

      button {
        flex: 1;
        min-width: 86px;
      }
    }
  </style>
</head>
<body>
  <main>
    <header>
      <h1>Sorting Visualizer</h1>
      <p>Bubble sort, animated one comparison at a time.</p>
    </header>

    <section class="visualizer" aria-label="Sorting algorithm visualizer">
      <div id="bars" aria-label="Array values shown as vertical bars"></div>

      <div class="controls">
        <button id="sort" type="button">Sort</button>
        <button id="shuffle" type="button">Shuffle</button>
        <button id="reset" type="button">Reset</button>
        <span id="status" aria-live="polite">Ready</span>
      </div>
    </section>
  </main>

  <script>
    (() => {
      "use strict";

      const initialArray = [
        42, 18, 76, 33, 91, 55, 12, 68, 27, 84,
        49, 7, 63, 38, 96, 22, 71, 45, 15, 59
      ];

      const barsElement = document.getElementById("bars");
      const sortButton = document.getElementById("sort");
      const shuffleButton = document.getElementById("shuffle");
      const resetButton = document.getElementById("reset");
      const statusElement = document.getElementById("status");

      let values = initialArray.slice();
      let comparisonIndex = 0;
      let passEnd = values.length - 1;
      let swappedInPass = false;
      let sortComplete = isAscending(values);
      let animationId = 0;
      let animating = false;

      function isAscending(array) {
        for (let i = 1; i < array.length; i++) {
          if (array[i - 1] > array[i]) return false;
        }
        return true;
      }

      function resetSortState() {
        comparisonIndex = 0;
        passEnd = values.length - 1;
        swappedInPass = false;
        sortComplete = values.length < 2 || isAscending(values);
      }

      function stopAnimation() {
        animationId++;
        animating = false;
        sortButton.disabled = false;
        shuffleButton.disabled = false;
        resetButton.disabled = false;
      }

      function render(activeA = -1, activeB = -1, complete = sortComplete) {
        barsElement.replaceChildren();

        const positiveMaximum = Math.max(0, ...values);
        const scaleMaximum = positiveMaximum || 1;
        const fragment = document.createDocumentFragment();

        values.forEach((value, index) => {
          const bar = document.createElement("div");
          const numericValue = Number(value);
          const proportionalHeight = Math.max(0, numericValue) / scaleMaximum * 100;

          bar.className = "bar";
          bar.style.height = proportionalHeight + "%";
          bar.dataset.value = String(value);
          bar.setAttribute("role", "img");
          bar.setAttribute("aria-label", `Value ${value}`);

          if (index === activeA || index === activeB) {
            bar.classList.add("comparing");
          } else if (complete) {
            bar.classList.add("complete");
          }

          const label = document.createElement("span");
          label.className = "bar-label";
          label.textContent = String(value);
          bar.appendChild(label);
          fragment.appendChild(bar);
        });

        barsElement.appendChild(fragment);
      }

      function sortStep() {
        if (sortComplete) {
          render(-1, -1, true);
          return true;
        }

        const left = comparisonIndex;
        const right = comparisonIndex + 1;

        if (values[left] > values[right]) {
          const temporary = values[left];
          values[left] = values[right];
          values[right] = temporary;
          swappedInPass = true;
        }

        comparisonIndex++;

        if (comparisonIndex >= passEnd) {
          if (!swappedInPass) {
            sortComplete = true;
          } else {
            passEnd--;
            comparisonIndex = 0;
            swappedInPass = false;

            if (passEnd <= 0) {
              sortComplete = true;
            }
          }
        }

        render(left, right, false);

        if (sortComplete) {
          render(-1, -1, true);
        }

        return sortComplete;
      }

      function setArray(array) {
        if (!Array.isArray(array)) {
          throw new TypeError("setArray(a) expects an array.");
        }

        if (!array.every(value => typeof value === "number" && Number.isFinite(value))) {
          throw new TypeError("All array elements must be finite numbers.");
        }

        stopAnimation();
        values = array.slice();
        resetSortState();
        statusElement.textContent = sortComplete ? "Sorted" : "Ready";
        render(-1, -1, sortComplete);
      }

      function shuffleArray() {
        stopAnimation();

        for (let i = values.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          const temporary = values[i];
          values[i] = values[j];
          values[j] = temporary;
        }

        resetSortState();
        statusElement.textContent = sortComplete ? "Sorted" : "Shuffled";
        render(-1, -1, sortComplete);
      }

      function animateSort() {
        if (animating || sortComplete) {
          statusElement.textContent = "Sorted";
          render(-1, -1, true);
          return;
        }

        animating = true;
        sortButton.disabled = true;
        shuffleButton.disabled = true;
        resetButton.disabled = true;
        statusElement.textContent = "Sorting…";

        const currentAnimation = ++animationId;

        function frame() {
          if (currentAnimation !== animationId) return;

          const complete = sortStep();

          if (complete) {
            animating = false;
            sortButton.disabled = false;
            shuffleButton.disabled = false;
            resetButton.disabled = false;
            statusElement.textContent = "Sorted";
            return;
          }

          requestAnimationFrame(frame);
        }

        requestAnimationFrame(frame);
      }

      sortButton.addEventListener("click", animateSort);
      shuffleButton.addEventListener("click", shuffleArray);
      resetButton.addEventListener("click", () => setArray(initialArray));

      window.viz = {
        array() {
          return values.slice();
        },
        setArray,
        sortStep,
        sorted() {
          return isAscending(values);
        }
      };

      render(-1, -1, sortComplete);
    })();
  </script>
</body>
</html>
